from functools import lru_cache

@lru_cache(maxsize=None)
def fib(n):
    if n <= 1: return n
    return fib(n-1) + fib(n-2)

# 격자 경로 수 (오른쪽/아래로만 이동)
@lru_cache(maxsize=None)
def paths(r, c):
    if r == 0 or c == 0: return 1
    return paths(r-1, c) + paths(r, c-1)

